pub fn add_futex_timer(expire: Timespec, task: &Arc<TaskControlBlock>, futex_key: usize) {
    let mut timers = TIMERS.lock();
    timers.push(TimerCondVar {
        expire,
        task: Arc::downgrade(&task),
        kind: TimerType::Futex,
        extra_data: futex_key,
    });
